// TrackRequest records metrics for a single request
func (m *CustomMetrics) TrackRequest(userID, method, endpoint, statusCode, userAgent, region string, duration time.Duration, reqSize, respSize float64) {
	m.requestsTotal.With(prometheus.Labels{
		"user_id":    userID,
		"method":     method,
		"endpoint":   endpoint,
		"status_code": statusCode,
		"user_agent": userAgent,
		"region":     region,
	}).Inc()

	m.requestDuration.With(prometheus.Labels{
		"user_id":  userID,
		"method":   method,
		"endpoint": endpoint,
		"region":   region,
	}).Observe(duration.Seconds())

	m.requestSize.With(prometheus.Labels{
		"user_id":  userID,
		"method":   method,
		"endpoint": endpoint,
	}).Observe(reqSize)

	m.responseSize.With(prometheus.Labels{
		"user_id":     userID,
		"method":      method,
		"endpoint":    endpoint,
		"status_code": statusCode,
	}).Observe(respSize)
}

// TrackError records an error metric
func (m *CustomMetrics) TrackError(userID, endpoint, errorType string) {
	m.errorsTotal.With(prometheus.Labels{
		"user_id":    userID,
		"endpoint":   endpoint,
		"error_type": errorType,
	}).Inc()
}

// IncrementActiveRequests increments the active request gauge
func (m *CustomMetrics) IncrementActiveRequests(userID, endpoint string) {
	m.activeRequests.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	}).Inc()
}

// DecrementActiveRequests decrements the active request gauge
func (m *CustomMetrics) DecrementActiveRequests(userID, endpoint string) {
	m.activeRequests.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	}).Dec()
}

// SetUserSessions sets the number of active sessions for a user
func (m *CustomMetrics) SetUserSessions(userID, region, sessionType string, count float64) {
	m.userSessionGauge.With(prometheus.Labels{
		"user_id":      userID,
		"region":       region,
		"session_type": sessionType,
	}).Set(count)
}

// instrumentedHandler wraps an HTTP handler with metric tracking
func instrumentedHandler(metrics *CustomMetrics, endpoint string, handler http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		region := r.Header.Get("X-Region")
		if region == "" {
			region = r.URL.Query().Get("region")
		}
		if region == "" {
			region = "unknown"
		}

		userAgent := r.UserAgent()
		if userAgent == "" {
			userAgent = "unknown"
		}

		// Track active requests
		metrics.IncrementActiveRequests(userID, endpoint)
		defer metrics.DecrementActiveRequests(userID, endpoint)

		// Wrap response writer to capture status code and size
		wrappedWriter := &responseWriterWrapper{
			ResponseWriter: w,
			statusCode:     http.StatusOK,
		}

		start := time.Now()
		handler(wrappedWriter, r)
		duration := time.Since(start)

		statusCode := fmt.Sprintf("%d", wrappedWriter.statusCode)
		reqSize := float64(r.ContentLength)
		if reqSize < 0 {
			reqSize = 0
		}

		metrics.TrackRequest(
			userID,
			r.Method,
			endpoint,
			statusCode,
			userAgent,
			region,
			duration,
			reqSize,
			float64(wrappedWriter.bytesWritten),
		)

		// Track errors (4xx and 5xx)
		if wrappedWriter.statusCode >= 400 && wrappedWriter.statusCode < 500 {
			metrics.TrackError(userID, endpoint, "client_error")
		} else if wrappedWriter.statusCode >= 500 {
			metrics.TrackError(userID, endpoint, "server_error")
		}
	}
}

// responseWriterWrapper captures status code and bytes written
type responseWriterWrapper struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (rw *responseWriterWrapper) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriterWrapper) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += n
	return n, err
}

// simulateTraffic generates fake traffic to populate metrics
func simulateTraffic(metrics *CustomMetrics) {
	users := []string{"user-001", "user-002", "user-003", "user-004", "user-005",
		"user-006", "user-007", "user-008", "user-009", "user-010"}
	regions := []string{"us-east-1", "us-west-2", "eu-west-1", "ap-southeast-1"}
	endpoints := []string{"/api/v1/data", "/api/v1/users", "/api/v1/orders", "/api/v1/search"}
	methods := []string{"GET", "POST", "PUT", "DELETE"}
	statusCodes := []string{"200", "201", "400", "404", "500"}
	userAgents := []string{"Mozilla/5.0", "curl/7.68", "Go-http-client/1.1", "Python-urllib/3.8"}
	errorTypes := []string{"timeout", "validation", "auth_failure", "rate_limit"}
	sessionTypes := []string{"web", "mobile", "api"}

	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		// Simulate multiple requests
		for i := 0; i < rand.Intn(10)+1; i++ {
			user := users[rand.Intn(len(users))]
			region := regions[rand.Intn(len(regions))]
			endpoint := endpoints[rand.Intn(len(endpoints))]
			method := methods[rand.Intn(len(methods))]
			status := statusCodes[rand.Intn(len(statusCodes))]
			agent := userAgents[rand.Intn(len(userAgents))]
			duration := time.Duration(rand.Intn(2000)) * time.Millisecond
			reqSize := float64(rand.Intn(10000))
			respSize := float64(rand.Intn(50000))

			metrics.TrackRequest(user, method, endpoint, status, agent, region, duration, reqSize, respSize)

			// Randomly track errors
			if rand.Float64() < 0.1 {
				errType := errorTypes[rand.Intn(len(errorTypes))]
				metrics.TrackError(user, endpoint, errType)
			}
		}

		// Update session gauges
		for _, user := range users {
			region := regions[rand.Intn(len(regions))]
			sessType := sessionTypes[rand.Intn(len(sessionTypes))]
			metrics.SetUserSessions(user, region, sessType, float64(rand.Intn(5)))
		}
	}
}

